import{_ as s,o as e,c as i,a5 as t}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：单相逆变器比例谐振电压控制","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相逆变器比例谐振电压控制","tags":["power-electronics"],"status":"learning","summary":"比例谐振控制（proportional resonant control / PR control）是一种适合正弦交流量的电压环（voltage loop）控制方法。比例项负责快速响应，谐振项专门在目标频率附近累积误差并给出校正量。"},"headers":[],"relativePath":"content/power/concepts/control/single-phase-inverter-pr-control.md","filePath":"content/power/concepts/control/single-phase-inverter-pr-control.md","lastUpdated":null}'),n={name:"content/power/concepts/control/single-phase-inverter-pr-control.md"};function l(o,a,p,r,c,h){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="概念-单相逆变器比例谐振电压控制" tabindex="-1">概念：单相逆变器比例谐振电压控制 <a class="header-anchor" href="#概念-单相逆变器比例谐振电压控制" aria-label="Permalink to &quot;概念：单相逆变器比例谐振电压控制&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>比例谐振控制（proportional resonant control / PR control）是一种适合正弦交流量的电压环（voltage loop）控制方法。比例项负责快速响应，谐振项专门在目标频率附近累积误差并给出校正量。</p><p>本节只讲一个概念：对 50 Hz 正弦输出，普通比例控制会留下交流稳态误差；PR 控制在 50 Hz 处提高增益，可以显著降低正弦稳态跟踪误差。</p><p>保密边界：不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。本节只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）的逆变器需要让输出电压跟随正弦参考。负载变重、LC 滤波器压降、直流母线变化都会让输出电压偏离参考。若只用普通比例控制，误差通常不会完全消失。</p><p>PR 控制常用于单相逆变器输出电压控制。它让固件在基波频率处更有“纠偏能力”，帮助输出 RMS 和波形跟随参考，同时仍然可以配合限幅、保护和状态机。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>比例控制像“看到误差就推一下”，但对持续旋转的正弦误差，它每一刻推的方向都在变，容易留下残余误差。PR 控制像一个只盯住 50 Hz 的记忆器：如果 50 Hz 分量长期存在误差，它会不断积累并补偿这一频率的误差。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>连续域常见表达是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Gpr(s) = Kp + Kr * 2*wc*s / (s^2 + 2*wc*s + w0^2)</span></span></code></pre></div><p>本节教学仿真用更直观的同步投影形式表示 50 Hz 谐振记忆：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>e = v_ref - v_out</span></span>
<span class="line"><span>xs += e * sin(theta) * dt</span></span>
<span class="line"><span>xc += e * cos(theta) * dt</span></span>
<span class="line"><span>u_res = Kr * (xs*sin(theta) + xc*cos(theta))</span></span>
<span class="line"><span>m_cmd = clamp(v_ref/Vdc + Kp*e + u_res/Vdc, -m_limit, m_limit)</span></span></code></pre></div><p>其中 <code>theta = 2*pi*50*t</code>。这不是公司内部实现，只是为了让你看清“谐振项如何记住目标频率误差”。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_pr_control.py</span></span></code></pre></div><p>观察顺序：</p><ul><li>先看 <code>v_ref</code> 和 <code>v_out</code>，确认输出电压跟随参考。</li><li>再看 <code>Voltage error e_v</code>，对比负载阶跃后误差是否恢复。</li><li>看 <code>m_cmd</code> 是否碰到限幅，避免把控制效果误判为过调制。</li><li>看 <code>i_load</code> 在负载从 48.4 ohm 变到 32 ohm 后是否增大。</li></ul><p>脚本默认保存并自动打开图片；如果无法自动打开，会打印完整图片路径。</p><p>一个仿真任务：对比没有谐振项和有谐振项时，负载阶跃后的 50 Hz 电压跟踪误差、调制命令和负载电流。</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_pr_control.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">resonant</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gain </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\inverter_pr_Kr_0.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_inverter_pr_control.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">resonant</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gain </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">80</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\inverter_pr_Kr_80.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件中可按下面链路理解：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ADC Vout, iL, Vdc</span></span>
<span class="line"><span>  -&gt; voltage reference from sine table or PLL angle</span></span>
<span class="line"><span>  -&gt; e_v = v_ref - v_out</span></span>
<span class="line"><span>  -&gt; PR voltage controller</span></span>
<span class="line"><span>  -&gt; modulation command limit</span></span>
<span class="line"><span>  -&gt; PWM compare update</span></span>
<span class="line"><span>  -&gt; over-current / over-voltage / saturation checks</span></span></code></pre></div><p>真实固件还要处理离散化、限幅、抗饱和、频率偏移、采样延迟和保护优先级。本节只把 PR 的基波误差校正讲清楚。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>错误理解：PR 控制就是 PI 控制换个名字。<br> 正确理解：比例积分（proportional integral / PI）擅长直流量零误差；PR 擅长交流正弦量在指定频率处小误差。</li><li>错误理解：PR 增益越大越好。<br> 正确理解：增益过大可能放大噪声、引起振荡、触发调制限幅或让 LC 谐振更难处理。</li><li>错误理解：只要 PR 控制误差小，就不用保护。<br> 正确理解：负载短路、过流、母线异常和采样故障仍然必须由保护逻辑处理。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释 <code>Kp</code>、<code>Kr</code>、<code>e_v</code>、<code>m_cmd</code> 各自代表什么。</li><li>能说出 PR 为什么比单纯比例控制更适合 50 Hz 正弦电压跟踪。</li><li>能根据图内参数框读出 Vdc、Vout_ref、f_out、L、C、负载阶跃、Kp、Kr、f_ctrl 和 t_end。</li><li>能解释为什么检查调制限幅是判断控制效果的必要步骤。</li><li>能基于 <code>single_phase_inverter_pr_control.py</code> 生成的仿真图准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么 <code>Kr=0</code> 时仍可能有明显的 50 Hz 跟踪误差？</li><li>如果把 <code>Kr</code> 继续加大，除了误差变小，还可能带来哪些风险？</li><li>负载从 <code>48.4 ohm</code> 变到 <code>32 ohm</code> 后，为什么要同时观察 <code>v_out</code>、<code>e_v</code>、<code>m_cmd</code> 和 <code>i_load</code>？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_inverter_pr_control.py</code> 看到 <code>Kr=80</code> 比 <code>Kr=0</code> 的 50 Hz 跟踪误差小很多。公司 UPS 逆变器电压环通常用 PR、PI 旋转坐标系，还是其他结构？</li><li>仿真里 <code>m_cmd</code> 没有触碰 <code>m_limit=0.95</code>。真实固件里 PR 输出限幅后，是否有抗饱和处理或故障计数？</li><li>负载从 <code>48.4 ohm</code> 变到 <code>32 ohm</code> 后，<code>i_load</code> 增大但 <code>v_out</code> 恢复到参考附近。真实调试时会怎样区分控制环带宽不足、LC 参数问题和限流保护介入？</li></ul>`,36)])])}const u=s(n,[["render",l]]);export{k as __pageData,u as default};
